sp_widget.client_script:
api.controller = function ($sce, spUtil) {
    const c = this;

    init();

    c.setLimit = function () {
        if (!c.data.canSavePreferences) return;
        savePreference("limit", c.data.limit).then(() => {});
    };

    c.goToFirstPage = function () {
        c.page = 1;
        getTableData();
    };

    c.goToPreviousPage = function () {
        if (c.page > 1) {
            c.page -= 1;
            getTableData();
        }
    };

    c.goToNextPage = function () {
        if (c.page < c.totalPages) {
            c.page += 1;
            getTableData();
        }
    };

    c.goToLastPage = function () {
        c.page = c.totalPages;
        getTableData();
    };

    c.sort = function (fieldName) {
        c.page = 1;
        let savePromise;

        if (c.data.orderBy === fieldName) {
            const orderDirection =
                c.data.orderDirection === "ASC" ? "DESC" : "ASC";

            savePromise = c.data.canSavePreferences
                ? savePreference("orderDirection", orderDirection)
                : Promise.resolve();
        } else {
            savePromise = c.data.canSavePreferences
                ? savePreference("orderBy", fieldName).then(() => {
                      savePreference("orderDirection", "ASC");
                  })
                : Promise.resolve();
        }

        savePromise.then(() => {
            getTableData();
        });
    };

    c.addField = function () {
        // Add to selected fields list
        c.selectedFieldsList.push(c.fieldToAdd);
        // Remove from unselected fields list
        const index = c.unselectedFieldsList.findIndex(
            (field) => field.name === c.fieldToAdd.name
        );
        c.unselectedFieldsList.splice(index, 1);
        // Reset the field to add
        c.fieldToAdd = null;
    };

    c.removeField = function () {
        // Add to unselected fields list
        c.unselectedFieldsList.push(c.fieldToRemove);
        // Remove from selected fields list
        const index = c.selectedFieldsList.findIndex(
            (field) => field.name === c.fieldToRemove.name
        );
        c.selectedFieldsList.splice(index, 1);
        // Reset the field to remove
        c.fieldToRemove = null;
    };

    c.moveFieldUp = function () {
        const index = c.selectedFieldsList.findIndex(
            (field) => field.name === c.fieldToRemove.name
        );
        if (index > 0) {
            const temp = c.selectedFieldsList[index - 1];
            c.selectedFieldsList[index - 1] = c.selectedFieldsList[index];
            c.selectedFieldsList[index] = temp;
        }
    };

    c.moveFieldDown = function () {
        const index = c.selectedFieldsList.findIndex(
            (field) => field.name === c.fieldToRemove.name
        );
        if (index < c.selectedFieldsList.length - 1) {
            const temp = c.selectedFieldsList[index + 1];
            c.selectedFieldsList[index + 1] = c.selectedFieldsList[index];
            c.selectedFieldsList[index] = temp;
        }
    };

    c.saveListView = function () {
        c.savingListView = true;

        const savePromise = c.data.canSavePreferences
            ? savePreference("columns", JSON.stringify(c.selectedFieldsList))
            : Promise.resolve();

        savePromise.then(() => {
            getTableColumns().then(() => {
                c.savingListView = false;
                document.getElementById(c.settingsDialogId).close();
            });
            getTableData();
        });
    };

    c.cancelListView = function () {
        c.cancelingListView = true;
        c.selectedFieldsList = angular.copy(c.data.columns);
        c.unselectedFieldsList = angular.copy(c.data.allColumnsAvailable);
        c.unselectedFieldsList = c.unselectedFieldsList.filter((field) => {
            return !c.selectedFieldsList.some(
                (selectedField) => selectedField.name === field.name
            );
        });
        c.fieldToAdd = null;
        c.fieldToRemove = null;
        c.cancelingListView = false;
        document.getElementById(c.settingsDialogId).close();
    };

    c.revertListViewToDefault = function () {
        c.revertingListView = true;
        c.server
            .get({
                action: "revertListViewToDefault",
                transactionId: c.data.transactionId,
                configurationRecordSysId: c.data.configurationRecordSysId,
            })
            .then((response) => {
                c.data.columns = response.data.columns;
                c.revertingListView = false;
                document.getElementById(c.settingsDialogId).close();
                getTableData();
            });
    };

    c.getFirstRecordIndex = function () {
        return (c.page - 1) * parseInt(c.data.limit, 10) + 1;
    };

    c.getLastRecordIndex = function () {
        const last = c.page * parseInt(c.data.limit, 10);
        return last > c.totalRecords ? c.totalRecords : last;
    };

    c.applyFilters = function () {
        c.appliedFilters = c.filters
            .filter((filter) => {
                return filter.value && filter.value !== "";
            })
            .map((filter) => {
                // Create a clean filter object to send to server
                return {
                    field: filter.field,
                    label: filter.label,
                    type: filter.type,
                    value: filter.value,
                    choiceValues: filter.choiceValues,
                    referenceTable: filter.referenceTable,
                    displayFields: filter.displayFields,
                    referenceQualifier: filter.referenceQualifier,
                    id: filter.id,
                };
            });

        c.page = 1;
        getTotalRecords();
        getTableData();
        getAppliedFiltersInfoMessage();
        document.getElementById(c.filtersDialogId).close();
    };

    c.cancelFilters = function () {
        // Reset filters to their applied state
        c.filters.forEach((filter) => {
            const appliedFilter = c.appliedFilters.find(
                (af) => af.field === filter.field
            );
            filter.value = appliedFilter ? appliedFilter.value : "";
        });
        document.getElementById(c.filtersDialogId).close();
    };

    function getTableColumns() {
        return c.server
            .get({
                action: "getTableColumns",
                transactionId: c.data.transactionId,
                configurationRecordSysId: c.data.configurationRecordSysId,
            })
            .then((response) => {
                c.data.columns = response.data.columns;
            });
    }

    function getTableData() {
        c.showSpinner = true;
        c.server
            .get({
                action: "getTableData",
                transactionId: c.data.transactionId,
                configurationRecordSysId: c.data.configurationRecordSysId,
                page: c.page,
                filters: c.appliedFilters || [],
            })
            .then((response) => {
                c.records = response.data.records;
                c.data.orderBy = response.data.orderBy;
                c.data.orderDirection = response.data.orderDirection;
                c.showSpinner = false;
            });
    }

    function getTotalRecords() {
        c.server
            .get({
                action: "getTotalRecords",
                transactionId: c.data.transactionId,
                configurationRecordSysId: c.data.configurationRecordSysId,
                filters: c.appliedFilters || [],
            })
            .then((response) => {
                c.totalRecords = response.data.totalRecords;
                c.totalPages = Math.ceil(c.totalRecords / c.data.limit);
            });
    }

    function initializeFilters() {
        c.filters = [];

        if (c.data.filterFields.length > 0) {
            c.data.filterFields.forEach((fieldConfig) => {
                const filter = {
                    field: fieldConfig.field,
                    label: fieldConfig.label,
                    type: fieldConfig.type,
                    value: "",
                    choiceValues: [],
                    loading: false,
                    id: spUtil.createUid("xxxx-xxxx"),
                };

                // Add reference-specific properties if it's a reference type
                if (fieldConfig.type === "reference") {
                    filter.referenceTable = fieldConfig.referenceTable;
                    filter.displayField = fieldConfig.displayField;
                    filter.searchFields = fieldConfig.searchFields;
                    filter.placeholder =
                        fieldConfig.placeholder ||
                        "Search " + fieldConfig.label;
                    filter.referenceQualifier = fieldConfig.referenceQualifier;
                    filter.pageSize = fieldConfig.pageSize;
                    filter.minimumInputLength =
                        fieldConfig.minimumInputLength || 3;
                    filter.displayFields = fieldConfig.displayFields;
                    filter.orderBy = fieldConfig.orderBy;
                    filter.orderDirection = fieldConfig.orderDirection;
                }

                // Preload choice values for choice type filters
                if (filter.type === "choice") {
                    loadChoiceValues(filter);
                }

                c.filters.push(filter);
            });
        }
    }

    function loadChoiceValues(filter) {
        filter.loading = true;
        c.server
            .get({
                action: "getChoiceValues",
                transactionId: c.data.transactionId,
                configurationRecordSysId: c.data.configurationRecordSysId,
                fieldName: filter.field,
            })
            .then((response) => {
                filter.choiceValues = response.data.choiceValues || [];
                filter.loading = false;
            })
            .catch(() => {
                filter.loading = false;
            });
    }

    function savePreference(preferenceName, preferenceValue) {
        if (!c.data.canSavePreferences) return Promise.resolve();

        return c.server.get({
            action: "savePreference",
            transactionId: c.data.transactionId,
            configurationRecordSysId: c.data.configurationRecordSysId,
            preferenceName: preferenceName,
            preferenceValue: preferenceValue,
        });
    }

    function getAppliedFiltersInfoMessage() {
        c.appliedFiltersHtml = $sce.trustAsHtml("<span></span>");
        c.server
            .get({
                action: "getAppliedFiltersInfoMessage",
                transactionId: c.data.transactionId,
                configurationRecordSysId: c.data.configurationRecordSysId,
                appliedFilters: c.appliedFilters || [],
            })
            .then((response) => {
                c.appliedFiltersHtml = $sce.trustAsHtml(
                    response.data.appliedFiltersHtml
                );
            });
    }

    function init() {
        c.totalRecords = 0;
        c.totalPages = 0;
        c.page = 1;
        c.records = [];

        c.fieldToAdd = null;
        c.fieldToRemove = null;

        c.settingsDialogId = spUtil.createUid("xxxx-xxxx");
        c.filtersDialogId = spUtil.createUid("xxxx-xxxx");
        c.limitSelectId = spUtil.createUid("xxxx-xxxx");

        getTotalRecords();
        getTableData();

        c.selectedFieldsList = angular.copy(c.data.columns);
        c.unselectedFieldsList = angular.copy(c.data.allColumnsAvailable);
        c.unselectedFieldsList = c.unselectedFieldsList.filter((field) => {
            return !c.selectedFieldsList.some(
                (selectedField) => selectedField.name === field.name
            );
        });

        if (c.data.canFilter) {
            c.filters = [];
            c.appliedFilters = [];
            c.appliedFiltersHtml = $sce.trustAsHtml("<span></span>");
            initializeFilters();
        }
    }
};

sp_widget.css:
#table-header {
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
}

#table-wrapper {
    width: 100%;
    overflow-x: auto;

    table {
        width: 100%;
        min-width: max-content;
        border-collapse: separate;
        border-spacing: 0 var(--scm-spacing-2);
        table-layout: fixed;

        thead {
            tr {
                background-color: var(--scm-color-horizon);
                height: var(--scm-spacing-5);
                border-radius: var(--scm-border-radius-small);

                th {
                    margin: 0;
                    text-align: left;
                    vertical-align: middle;
                    font-weight: var(--scm-font-weight-semibold);
                    font-size: var(--scm-icon-size-xsmall);
                    color: var(--scm-color-gray);
                    background-color: var(--scm-color-horizon);
                    height: var(--scm-spacing-5);
                    width: 200px;
                    min-width: 200px;
                    padding-left: var(--scm-padding-2);
                    padding-right: var(--scm-padding-2);
                    white-space: nowrap;
                    overflow: hidden;
                    text-overflow: ellipsis;

                    &:first-child {
                        border-top-left-radius: var(--scm-border-radius-small);
                        border-bottom-left-radius: var(
                            --scm-border-radius-small
                        );
                    }

                    &:last-child {
                        border-top-right-radius: var(--scm-border-radius-small);
                        border-bottom-right-radius: var(
                            --scm-border-radius-small
                        );
                    }
                }
            }
        }

        tbody {
            tr {
                &:hover {
                    td {
                        background-color: var(--scm-color-blue-tint-3);

                        &:hover {
                            background-color: var(--scm-color-blue-tint-2);
                        }
                    }
                }

                td {
                    margin: 0;
                    text-align: left;
                    vertical-align: middle;
                    font-weight: var(--scm-font-weight-regular);
                    font-size: var(--scm-icon-size-xsmall);
                    background-color: var(--scm-color-sc-white);
                    height: var(--scm-spacing-5);
                    width: 200px;
                    min-width: 200px;
                    padding-left: var(--scm-padding-2);
                    padding-right: var(--scm-padding-2);
                    white-space: nowrap;
                    overflow: hidden;
                    text-overflow: ellipsis;
                    a {
                        text-decoration: none !important;
                        border: none !important;
                        outline: none !important;
                        box-shadow: none !important;
                        color: inherit !important;

                        &:visited,
                        &:focus,
                        &:active {
                            text-decoration: none !important;
                            border: none !important;
                            outline: none !important;
                            box-shadow: none !important;
                            color: inherit !important;
                        }

                        &:hover {
                            text-decoration: none !important;
                            border: none !important;
                            outline: none !important;
                            box-shadow: none !important;
                            font-weight: var(--scm-font-weight-semibold);
                            color: inherit !important;
                        }
                    }

                    &:first-child {
                        border-top-left-radius: var(--scm-border-radius-medium);
                        border-bottom-left-radius: var(
                            --scm-border-radius-medium
                        );
                    }

                    &:last-child {
                        border-top-right-radius: var(
                            --scm-border-radius-medium
                        );
                        border-bottom-right-radius: var(
                            --scm-border-radius-medium
                        );
                    }
                }
            }
        }
    }
}

#controller-wrapper {
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
    padding-left: var(--scm-padding-2);
    padding-right: var(--scm-padding-2);

    div {
        display: flex;
        align-items: center;
        gap: var(--scm-spacing-2);
    }

    #metadata-wrapper {
        display: flex;
        flex-direction: row;
        align-items: center;

        div {
            color: var(--scm-color-gray);
            font-weight: var(--scm-font-weight-light);
            font-size: var(--scm-font-size-xsmall);
            margin-right: var(--scm-spacing-4);
        }
    }

    sdx-dialog sdx-dialog-toggle sdx-icon {
        color: var(--scm-color-int-blue);
        cursor: pointer;
    }

    sdx-dialog sdx-dialog-toggle sdx-icon:hover {
        color: var(--scm-color-int-blue-active);
    }
}

#filters-wrapper {
    margin-top: var(--scm-spacing-6);
    margin-bottom: var(--scm-spacing-6);

    #filters-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-bottom: var(--scm-spacing-3);
        gap: var(--scm-spacing-4);
    }

    #filters-form {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
        gap: var(--scm-spacing-3);
    }
}

#applied-filters-wrapper {
    margin-top: var(--scm-spacing-3);
    margin-bottom: var(--scm-spacing-3);

    #applied-filters-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-bottom: var(--scm-spacing-1);
        font-weight: var(--scm-font-weight-semibold);
        font-size: var(--scm-icon-size-xsmall);
        color: var(--scm-color-gray);
    }

    #applied-filters-list {
        color: var(--scm-color-gray);
        font-weight: var(--scm-font-weight-light);
        font-size: var(--scm-font-size-xsmall);

        .filter-separator {
            margin: 0 var(--scm-spacing-2);
            font-weight: var(--scm-font-weight-semibold);
            color: var(--scm-color-int-blue);
        }
    }
}

sp_widget.link:
function link(scope, element, attrs, controller) {
    $(document).on("keydown", function (event) {
        const settingsDialogElement = document.getElementById(
            controller.settingsDialogId
        );
        const filtersDialogElement = document.getElementById(
            controller.filtersDialogId
        );
        switch (event.keyCode) {
            case 27: // escape
                if (settingsDialogElement) settingsDialogElement.close();
                if (filtersDialogElement) filtersDialogElement.close();
                break;

            case 13: // enter
                if (settingsDialogElement) controller.saveListView();
                if (filtersDialogElement) controller.applyFilters();
                break;
        }
    });
}

sp_widget.script:
// TODO: Validate input

(function () {
    const transactionId = input?.transactionId || gs.generateGUID();
    const configurationRecordSysId =
        input?.configurationRecordSysId || options?.configurationRecordSysId;

    const logger = new Logger({
        transactionId: transactionId,
        source: "scm-table.server.js",
        includeTimeStamp: true,
        includeUserInfo: true,
        includeSessionId: true,
    });

    if (!configurationRecordSysId) {
        data.redirectTo404 = true;
        logger.error("Configuration record Sys ID is missing");
        return;
    }

    data.transactionId = transactionId;
    data.configurationRecordSysId = configurationRecordSysId;

    let widgetHelper;
    try {
        widgetHelper = new SCMTableWidgetHelper({
            transactionId: transactionId,
            configurationRecordSysId: configurationRecordSysId,
        });
    } catch (error) {
        data.redirectTo404 = true;
        logger.error({
            message: "Error initializing SCMTableWidgetHelper",
            error: error.message,
        });
        return;
    }

    if (input && input.action === "savePreference") {
        if (!widgetHelper.canSavePreferences()) return;

        widgetHelper.saveUserPreference(
            input.preferenceName,
            input.preferenceValue
        );
        return;
    }

    if (input && input.action === "getAppliedFiltersInfoMessage") {
        data.appliedFiltersHtml = widgetHelper.getAppliedFiltersInfoMessage(
            input.appliedFilters
        );
        return;
    }

    if (input && input.action === "getTotalRecords") {
        data.totalRecords = widgetHelper.getTotalRecords(input.filters);
        return;
    }

    if (input && input.action === "getChoiceValues") {
        data.choiceValues = widgetHelper.getChoiceValues(input.fieldName);
        return;
    }

    if (input && input.action === "getTableColumns") {
        data.columns = widgetHelper.getTableColumns();
        return;
    }

    if (input && input.action === "revertListViewToDefault") {
        widgetHelper.saveUserPreference(
            "columns",
            JSON.stringify(widgetHelper.getDefaultColumns())
        );
        data.columns = widgetHelper.getDefaultColumns();
        return;
    }

    if (input && input.action === "getTableData") {
        data.records = widgetHelper.getTableData({
            filters: input.filters,
            page: input.page,
        });
        data.orderDirection = widgetHelper.getOrderDirection();
        data.orderBy = widgetHelper.getOrderBy();
        return;
    }

    //Page title
    data.title = widgetHelper.getPageTitle();

    // New record button
    data.showNewRecordButton = widgetHelper.canCreate();

    // Redirection to detail view page
    data.detailViewPage = widgetHelper.getDetailViewPage();
    data.idField = widgetHelper.getIdField();

    // Table filtering
    data.canFilter = widgetHelper.canFilter();
    data.filterFields = widgetHelper.getFilterFields();
    data.limit = widgetHelper.getTableLimit();

    // Preferences
    data.canSavePreferences = widgetHelper.canSavePreferences();

    // Columns
    data.allColumnsAvailable = widgetHelper.getAllAvailableColumns();
    data.columns = widgetHelper.getTableColumns();

    // Configuration record id
    data.configurationRecordSysId = configurationRecordSysId;
})();
